"""Dependency-free application shell kept separate from the API implementation."""

HTML = r'''<!doctype html>
<html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<meta name="color-scheme" content="light dark"><title>Civics Radar</title>
<style>
:root{--ink:#182321;--muted:#62706c;--paper:#f5f3ec;--card:#fffdf7;--line:#d8d8ce;--brand:#085c55;--accent:#d97836;--soft:#dceae6;--focus:#156fdb}*{box-sizing:border-box}body{margin:0;font:16px/1.5 ui-sans-serif,system-ui;color:var(--ink);background:var(--paper)}button,input,select{font:inherit}button,.button{border:0;border-radius:.55rem;padding:.65rem .9rem;background:var(--brand);color:white;cursor:pointer}button.secondary{background:transparent;color:var(--brand);border:1px solid var(--brand)}button:focus-visible,a:focus-visible,input:focus-visible,select:focus-visible{outline:3px solid var(--focus);outline-offset:2px}.shell{display:grid;grid-template-columns:240px 1fr;min-height:100vh}aside{padding:1.4rem;background:#123b37;color:white}.logo{font:bold 1.35rem Georgia,serif;margin-bottom:2rem}.nav{display:grid;gap:.35rem}.nav button{background:transparent;text-align:left}.nav button.active{background:#fff2}.account{margin-top:2rem;font-size:.85rem;color:#d5e5e1}main{padding:clamp(1rem,3vw,2.5rem);max-width:1350px;width:100%}.top{display:flex;justify-content:space-between;gap:1rem;align-items:start}h1,h2,h3{font-family:Georgia,serif;line-height:1.15}.eyebrow{color:var(--accent);text-transform:uppercase;letter-spacing:.09em;font-weight:700;font-size:.78rem}.muted{color:var(--muted)}.grid{display:grid;grid-template-columns:repeat(3,1fr);gap:1rem}.card{background:var(--card);border:1px solid var(--line);border-radius:.8rem;padding:1rem;margin:1rem 0}.bill{cursor:pointer}.bill:hover{border-color:var(--brand)}.row{display:flex;gap:.6rem;align-items:center;flex-wrap:wrap}.pill{padding:.2rem .55rem;border-radius:99px;background:var(--soft);font-size:.8rem}.filters{display:grid;grid-template-columns:2fr 1fr 1fr auto;gap:.6rem}.filters input,.filters select,.field{padding:.65rem;border:1px solid var(--line);border-radius:.45rem;background:var(--card);color:var(--ink)}.view[hidden],#login[hidden]{display:none}.empty{text-align:center;padding:3rem}.notice{border-left:4px solid var(--accent)}dialog{max-width:760px;width:calc(100% - 2rem);border:0;border-radius:1rem;padding:1.4rem;background:var(--card);color:var(--ink)}dialog::backdrop{background:#0018}.pagination{display:flex;justify-content:space-between;align-items:center;margin:1rem 0}.skip{position:absolute;left:-999px}.skip:focus{left:1rem;top:1rem;background:white;padding:.5rem;z-index:5}@media(max-width:800px){.shell{grid-template-columns:1fr}aside{position:sticky;top:0;z-index:3;padding:.8rem}.logo{margin:0}.nav{display:flex;overflow:auto;margin-top:.7rem}.account{display:none}.grid{grid-template-columns:1fr}.filters{grid-template-columns:1fr}.top{display:block}}
</style></head><body><a class="skip" href="#content">Skip to content</a><div class="shell"><aside><div class="logo">◉ Civics Radar</div><nav class="nav" aria-label="Primary"></nav><div class="account" id="account"></div></aside><main id="content"><section id="login"><p class="eyebrow">Secure workspace</p><h1>Track policy with context.</h1><p class="muted">Enter the API token issued by your administrator. It stays in this browser tab and is never placed in a URL.</p><form id="loginForm" class="card"><label>Bearer token<br><input class="field" id="token" type="password" autocomplete="off" required></label> <button>Open workspace</button><p id="loginError" role="alert"></p></form></section><div id="app" hidden><div class="top"><div><p class="eyebrow">Policy intelligence</p><h1 id="title">Feed</h1><p class="muted" id="subtitle"></p></div><button class="secondary" id="logout">Lock</button></div>
<section class="view" data-view="Feed"><div class="grid" id="metrics"></div><div id="feed"></div></section>
<section class="view" data-view="Bills" hidden><div class="filters"><input id="search" aria-label="Search bills" placeholder="Search title, summary, or number"><select id="jurisdiction" aria-label="Jurisdiction"><option value="">All jurisdictions</option><option>US</option><option>CA</option><option>TX</option><option>MO</option></select><select id="sort" aria-label="Sort"><option value="updated_at">Recently updated</option><option value="introduced_at">Recently introduced</option><option value="title">Title</option></select><button id="filter">Apply</button></div><div id="bills"></div><div class="pagination"><button class="secondary" id="prev">Previous</button><span id="page"></span><button class="secondary" id="next">Next</button></div></section>
<section class="view" data-view="Alerts" hidden><div id="alerts"></div></section><section class="view" data-view="Saved Views" hidden><form id="saveForm" class="card row"><input class="field" id="viewName" placeholder="View name" required maxlength="100"><button>Save current bill filters</button></form><div id="views"></div></section>
<section class="view" data-view="Settings" hidden><div class="card"><h2>Interests</h2><form id="interestsForm"><div id="interestChoices"></div><label>Minimum severity <select class="field" id="minSeverity"><option>low</option><option>medium</option><option>high</option></select></label><label>Jurisdictions <input class="field" id="interestJurisdictions" value="all" placeholder="all or US,MO"></label> <button>Save interests</button></form></div><div class="card"><h2>Notification settings</h2><form id="prefs"><label>Digest frequency <select class="field" id="frequency"><option>instant</option><option>daily</option><option>weekly</option><option>off</option></select></label><fieldset><legend>Channels</legend><label><input type="checkbox" value="in_app" checked> In app</label> <label><input type="checkbox" value="email"> Email</label> <label><input type="checkbox" value="telegram"> Telegram</label></fieldset><label>Email <input class="field" id="notificationEmail" type="email"></label><label>Telegram chat ID <input class="field" id="telegramChatId" pattern="-?[0-9]{1,20}"></label> <button>Save settings</button></form></div></section>
<section class="view" data-view="Admin" hidden><div class="card"><h2>Operations</h2><div id="operations"></div></div><div class="card"><h2>Provider health</h2><div id="providers"></div></div><div class="card"><h2>Taxonomy</h2><form id="categoryForm" class="row"><input class="field" id="categorySlug" placeholder="category-slug" required pattern="[a-z0-9]+(?:-[a-z0-9]+)*"><input class="field" id="categoryName" placeholder="Category name" required><input class="field" id="categoryDescription" placeholder="Neutral description" required minlength="5"><input class="field" id="categoryExamples" placeholder="term, phrase"><button>Add category</button></form><div id="adminCategories"></div></div><div class="card"><h2>Ingestion history</h2><div id="runs"></div></div></section></div></main></div><dialog id="detail"><button class="secondary" id="closeDetail" aria-label="Close detail">Close</button><div id="detailBody"></div></dialog>
<script>
const S={token:sessionStorage.getItem('civicsToken'),page:1,pages:1,dash:null};const esc=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
async function api(url,opt={}){const r=await fetch(url,{...opt,headers:{'Content-Type':'application/json',Authorization:`Bearer ${S.token}`,...opt.headers}});if(r.status===204)return null;if(!r.ok)throw new Error((await r.json().catch(()=>({}))).detail||`Request failed (${r.status})`);return r.json()}
const card=b=>`<article class="card bill" tabindex="0" role="button" data-id="${b.id}"><div class="row"><strong>${esc(b.bill_number)}</strong><span class="pill">${esc(b.jurisdiction_code)}</span><span class="pill">${esc(b.status)}</span></div><h3>${esc(b.title)}</h3><p>${esc(b.summary||b.user_summary)}</p></article>`;
async function start(){try{const me=await api('/api/me');S.dash=await api('/api/dashboard');login.hidden=true;app.hidden=false;account.textContent=`${me.user.email} · ${me.account?.name||'System'}`;const names=['Feed','Bills','Alerts','Saved Views','Settings',...(me.user.role==='admin'||me.user.role==='system_admin'?['Admin']:[])];document.querySelector('.nav').innerHTML=names.map((n,i)=>`<button class="${i?'':'active'}" data-nav="${n}">${n}</button>`).join('');bindNav();renderFeed();await Promise.all([loadBills(),loadViews()]);}catch(e){loginError.textContent=e.message}}
function bindNav(){document.querySelectorAll('[data-nav]').forEach(b=>b.onclick=async()=>{document.querySelectorAll('[data-nav]').forEach(x=>x.classList.toggle('active',x===b));document.querySelectorAll('.view').forEach(v=>v.hidden=v.dataset.view!==b.dataset.nav);title.textContent=b.dataset.nav;if(b.dataset.nav==='Alerts')renderAlerts();if(b.dataset.nav==='Settings')loadSettings();if(b.dataset.nav==='Admin')loadAdmin()})}
function renderFeed(){const d=S.dash;metrics.innerHTML=[['Matched bills',d.matches.length],['Unread alerts',d.notifications.filter(n=>n.status!=='read').length],['Interests',d.interests.length]].map(x=>`<div class="card"><span class="muted">${x[0]}</span><h2>${x[1]}</h2></div>`).join('');feed.innerHTML=d.matches.length?d.matches.map(m=>card({...m,id:m.bill_id,summary:m.user_summary})).join(''):'<div class="empty">No matched bills yet.</div>';wireBills()}
async function loadBills(){const p=new URLSearchParams({page:S.page,sort:sort.value});if(search.value)p.set('search',search.value);if(jurisdiction.value)p.set('jurisdiction',jurisdiction.value);const d=await api('/api/bills?'+p);S.pages=d.pages;bills.innerHTML=d.items.map(card).join('')||'<div class="empty">No bills match these filters.</div>';page.textContent=`Page ${d.page} of ${Math.max(d.pages,1)} · ${d.total} bills`;prev.disabled=S.page<=1;next.disabled=S.page>=d.pages;wireBills()}
function wireBills(){document.querySelectorAll('.bill').forEach(x=>{x.onclick=()=>showBill(x.dataset.id);x.onkeydown=e=>{if(e.key==='Enter')showBill(x.dataset.id)}})}
async function showBill(id){const d=await api('/api/bills/'+id),b=d.bill;detailBody.innerHTML=`<p class="eyebrow">${esc(b.jurisdiction_code)} · ${esc(b.bill_number)}</p><h2>${esc(b.title)}</h2><p>${esc(b.summary)}</p><p><a href="${esc(d.official_sources.record)}" target="_blank" rel="noopener">Official record</a> · <a href="${esc(d.official_sources.text)}" target="_blank" rel="noopener">Official text</a></p><p class="muted">${esc(d.audit_disclaimer)}</p><h3>Audit provenance</h3>${d.audit_runs.map(r=>`<p>${esc(r.provider)} · ${esc(r.model||'local')} · prompt ${esc(r.prompt_version)} · taxonomy ${esc(r.taxonomy_version)} · ${esc(r.completed_at)}</p>`).join('')||'<p>Pending audit.</p>'}<h3>Timeline</h3>${d.timeline.map(a=>`<p><strong>${esc(a.action_date)}</strong> · ${esc(a.description)}</p>`).join('')||'<p>No action history supplied.</p>'}<h3>Versions</h3>${d.versions.map(v=>`<p>${esc(v.created_at)} · ${esc(v.text_hash)}</p>`).join('')}<h3>Flags</h3>${d.flags.map(f=>`<div class="card notice"><strong>${esc(f.name)} · ${esc(f.severity)} · ${Math.round(f.confidence*100)}%</strong><p>${esc(f.rationale)}</p><small>${esc(f.citation)}</small><div class="row"><button class="secondary" data-feedback="wrong_tag" data-flag="${f.id}">Wrong tag</button><button class="secondary" data-feedback="severity_too_high" data-flag="${f.id}">Severity too high</button><button class="secondary" data-feedback="severity_too_low" data-flag="${f.id}">Severity too low</button><button class="secondary" data-feedback="not_relevant" data-flag="${f.id}">Not relevant</button></div></div>`).join('')}`;detail.showModal();detailBody.querySelectorAll('[data-feedback]').forEach(x=>x.onclick=async()=>{await api('/api/audit-flags/'+x.dataset.flag+'/feedback',{method:'POST',body:JSON.stringify({feedback_type:x.dataset.feedback,note:''})});x.disabled=true;x.textContent='Feedback saved'})}
function renderAlerts(){alerts.innerHTML=S.dash.notifications.map(n=>`<article class="card ${n.status==='read'?'':'notice'}"><h3>${esc(n.title)}</h3><p>${esc(n.body)}</p>${n.status!=='read'?`<button data-read="${n.id}">Mark read</button>`:''}</article>`).join('')||'<div class="empty">You are all caught up.</div>';document.querySelectorAll('[data-read]').forEach(b=>b.onclick=async()=>{await api('/api/notifications/'+b.dataset.read+'/read',{method:'PATCH'});S.dash=await api('/api/dashboard');renderAlerts()})}
async function loadViews(){const v=await api('/api/saved-views');views.innerHTML=v.map(x=>`<article class="card row"><strong>${esc(x.name)}</strong><button class="secondary" data-apply="${x.id}">Apply</button><button class="secondary" data-delete="${x.id}">Delete</button></article>`).join('')||'<div class="empty">No saved views yet.</div>';document.querySelectorAll('[data-apply]').forEach(b=>b.onclick=()=>{const x=v.find(item=>String(item.id)===b.dataset.apply),f=x?.filters||{};search.value=f.search||'';jurisdiction.value=f.jurisdiction||'';sort.value=f.sort||'updated_at';S.page=1;document.querySelector('[data-nav="Bills"]').click();loadBills()});document.querySelectorAll('[data-delete]').forEach(b=>b.onclick=async()=>{await api('/api/saved-views/'+b.dataset.delete,{method:'DELETE'});loadViews()})}
async function loadSettings(){const [cats,d,p]=await Promise.all([api('/api/categories'),api('/api/dashboard'),api('/api/notification-preferences')]);const active=new Set(d.interests.map(x=>x.slug));interestChoices.innerHTML=cats.filter(x=>x.active).map(x=>`<label><input type="checkbox" value="${esc(x.slug)}" ${active.has(x.slug)?'checked':''}> ${esc(x.name)}</label> `).join('');if(d.interests[0]){minSeverity.value=d.interests[0].min_severity;interestJurisdictions.value=d.interests[0].jurisdictions}frequency.value=p.digest_frequency;const channels=new Set(p.channels);prefs.querySelectorAll('input[type="checkbox"]').forEach(x=>x.checked=channels.has(x.value));notificationEmail.value=p.notification_email||'';telegramChatId.placeholder=p.telegram_chat_configured?'Configured; enter a value to replace':''}
async function loadAdmin(){const [d,cats]=await Promise.all([api('/api/admin/ops'),api('/api/categories')]);providers.innerHTML=Object.entries(d.providers).map(([k,v])=>`<p><strong>${esc(k)}</strong>: ${esc(v.status)}</p>`).join('');operations.innerHTML=`<p>Audit queue: ${esc(JSON.stringify(d.audit_queue))}</p><p>Notification queue: ${esc(JSON.stringify(d.notification_queue))}</p><p>Email: ${esc(d.delivery.email)} · Telegram: ${esc(d.delivery.telegram)} · Feedback: ${esc(d.feedback_count)}</p>`;runs.innerHTML=d.recent_ingestion_runs.map(r=>`<p>${esc(r.source_name)}${r.jurisdiction_code?' · '+esc(r.jurisdiction_code):''} · ${esc(r.status)} · ${esc(r.completed_at)}</p>`).join('')||'<p>No runs recorded.</p>';adminCategories.innerHTML=cats.map(c=>`<p class="row"><strong>${esc(c.name)}</strong><span>${c.active?'active':'inactive'}</span><button class="secondary" data-category="${c.id}" data-active="${c.active?0:1}">${c.active?'Deactivate':'Reactivate'}</button></p>`).join('');adminCategories.querySelectorAll('[data-category]').forEach(x=>x.onclick=async()=>{await api('/api/admin/categories/'+x.dataset.category,{method:'PATCH',body:JSON.stringify({active:x.dataset.active==='1'})});loadAdmin()})}
loginForm.onsubmit=e=>{e.preventDefault();S.token=token.value;sessionStorage.setItem('civicsToken',S.token);start()};logout.onclick=()=>{sessionStorage.removeItem('civicsToken');location.reload()};closeDetail.onclick=()=>detail.close();filter.onclick=()=>{S.page=1;loadBills()};prev.onclick=()=>{S.page--;loadBills()};next.onclick=()=>{S.page++;loadBills()};saveForm.onsubmit=async e=>{e.preventDefault();await api('/api/saved-views',{method:'POST',body:JSON.stringify({name:viewName.value,filters:{search:search.value,jurisdiction:jurisdiction.value,sort:sort.value}})});viewName.value='';loadViews()};interestsForm.onsubmit=async e=>{e.preventDefault();await api('/api/interests',{method:'POST',body:JSON.stringify({category_slugs:[...interestChoices.querySelectorAll('input:checked')].map(x=>x.value),min_severity:minSeverity.value,jurisdictions:interestJurisdictions.value.split(',').map(x=>x.trim()).filter(Boolean)})});S.dash=await api('/api/dashboard');renderFeed()};prefs.onsubmit=async e=>{e.preventDefault();const body={digest_frequency:frequency.value,channels:[...prefs.querySelectorAll('input:checked')].map(x=>x.value)};if(notificationEmail.value)body.notification_email=notificationEmail.value;if(telegramChatId.value)body.telegram_chat_id=telegramChatId.value;await api('/api/notification-preferences',{method:'POST',body:JSON.stringify(body)})};categoryForm.onsubmit=async e=>{e.preventDefault();await api('/api/admin/categories',{method:'POST',body:JSON.stringify({slug:categorySlug.value,name:categoryName.value,description:categoryDescription.value,examples_positive:categoryExamples.value})});categoryForm.reset();loadAdmin()};if(S.token)start();
</script></body></html>'''
